diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 706cb828acc6..6cbaacfe7504 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -4132,24 +4132,45 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
                                     m_Value(Ov)),
                        m_OneUse(m_ICmp(Pred, m_ExtractValue<0>(m_Deferred(WOV)),
                                        m_APInt(C2))))) &&
-      (WO->getBinaryOp() == Instruction::Add ||
-       WO->getBinaryOp() == Instruction::Sub) &&
-      (ICmpInst::isEquality(Pred) ||
-       WO->isSigned() == ICmpInst::isSigned(Pred)) &&
       match(WO->getRHS(), m_APInt(C1))) {
-    bool Overflow;
-    APInt NewC = WO->getBinaryOp() == Instruction::Add
-                     ? (ICmpInst::isSigned(Pred) ? C2->ssub_ov(*C1, Overflow)
-                                                 : C2->usub_ov(*C1, Overflow))
-                     : (ICmpInst::isSigned(Pred) ? C2->sadd_ov(*C1, Overflow)
-                                                 : C2->uadd_ov(*C1, Overflow));
-    if (!Overflow || ICmpInst::isEquality(Pred)) {
+    // Handle add/sub overflow patterns:
+    //   overflow | icmp pred (result +/- C1), C2  -->  overflow | icmp pred X, C2 -/+ C1
+    if ((WO->getBinaryOp() == Instruction::Add ||
+         WO->getBinaryOp() == Instruction::Sub) &&
+        (ICmpInst::isEquality(Pred) ||
+         WO->isSigned() == ICmpInst::isSigned(Pred))) {
+      bool Overflow;
+      APInt NewC = WO->getBinaryOp() == Instruction::Add
+                       ? (ICmpInst::isSigned(Pred) ? C2->ssub_ov(*C1, Overflow)
+                                                   : C2->usub_ov(*C1, Overflow))
+                       : (ICmpInst::isSigned(Pred) ? C2->sadd_ov(*C1, Overflow)
+                                                   : C2->uadd_ov(*C1, Overflow));
+      if (!Overflow || ICmpInst::isEquality(Pred)) {
+        Value *NewCmp = Builder.CreateICmp(
+            Pred, WO->getLHS(), ConstantInt::get(WO->getLHS()->getType(), NewC));
+        return BinaryOperator::CreateOr(Ov, NewCmp);
+      }
+    }
+    // For unsigned multiplication with overflow:
+    //   overflow | (product u> C2)
+    // When overflow occurs, the wrapped product is (x * c) % 2^N.
+    // The maximum overflow product is c - 1.
+    // If C2 >= c - 1, overflow products never satisfy (product > C2).
+    // So the expression simplifies to just the overflow condition:
+    //   x > floor((2^N - 1) / c)
+    if (WO->getBinaryOp() == Instruction::Mul && !WO->isSigned() &&
+        ICmpInst::isUnsigned(Pred) && !ICmpInst::isEquality(Pred) &&
+        C2->uge(*C1 - 1)) {
+      // Compute threshold = (2^N - 1) / C1
+      unsigned BitWidth = C2->getBitWidth();
+      APInt Threshold = APInt::getMaxValue(BitWidth).udiv(*C1);
       Value *NewCmp = Builder.CreateICmp(
-          Pred, WO->getLHS(), ConstantInt::get(WO->getLHS()->getType(), NewC));
-      return BinaryOperator::CreateOr(Ov, NewCmp);
+          Pred, WO->getLHS(), ConstantInt::get(WO->getLHS()->getType(), Threshold));
+      return replaceInstUsesWith(I, NewCmp);
     }
   }

+
   // (~x) | y  -->  ~(x & (~y))  iff that gets rid of inversions
   if (sinkNotIntoOtherHandOfLogicalOp(I))
     return &I;

